fn main() {
    use std::collections::HashSet;

    let secret = b"my-super-secret-key-for-jwt-signing";

    let now = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap()
        .as_secs() as usize;

    let claims = Claims {
        sub: "user-42".to_string(),
        exp: now + 3600,
        iat: now,
        nbf: Some(now),
        iss: Some("my-auth-service".to_string()),
        aud: Some(vec!["my-api".to_string()]),
        email: Some("alice@example.com".to_string()),
        name: Some("Alice".to_string()),
        roles: Some(vec!["admin".to_string(), "editor".to_string()]),
    };

    let token = jsonwebtoken::encode(
        &Header::new(Algorithm::HS256),
        &claims,
        &EncodingKey::from_secret(secret),
    )
    .expect("Failed to encode token");

    println!("Generated JWT: {}", &token[..50]);
    println!("...");

    // Verify using the JwtVerifier
    let config = JwtVerifierConfig {
        allowed_algorithms: vec![Algorithm::HS256, Algorithm::HS384, Algorithm::HS512],
        secret: Some(secret.to_vec()),
        required_issuer: Some("my-auth-service".to_string()),
        required_audience: Some(HashSet::from(["my-api".to_string()])),
        validate_exp: true,
        validate_nbf: true,
        leeway_seconds: 30,
        ..Default::default()
    };

    let verifier = JwtVerifier::new(config);

    let auth_header = format!("Bearer {}", token);
    match verifier.verify_from_auth_header(&auth_header) {
        Ok(user_info) => {
            println!("\nToken verified successfully!");
            println!("User ID: {}", user_info.user_id);
            println!("Email: {:?}", user_info.email);
            println!("Name: {:?}", user_info.name);
            println!("Roles: {:?}", user_info.roles);
            println!("Issuer: {:?}", user_info.issuer);
        }
        Err(e) => {
            eprintln!("Token verification failed: {}", e);
        }
    }

    // Demonstrate convenience function
    match verify_jwt_from_request(
        Some(&auth_header),
        secret,
        vec![Algorithm::HS256],
        Some("my-auth-service"),
        Some(HashSet::from(["my-api".to_string()])),
    ) {
        Ok(user_info) => {
            println!("\nConvenience function verification succeeded!");
            println!("User: {} ({})", user_info.user_id, user_info.name.unwrap_or_default());
        }
        Err(e) => {
            eprintln!("Convenience function failed: {}", e);
        }
    }
}